const input = $input.first().json;

const memberName = input['Member Name'] || '';
const firstName = input['Contact First Name'] || '';
const email = input['Contact Email'] || '';
const stationCode = input['Station Code'] || '';
const ticketsReceived = parseInt(input['Tickets Received'] || '0', 10);
const eprPosted = parseInt(input['EPR Posted'] || '0', 10);
const threshold = parseInt(input['Compliance Threshold %'] || '90', 10);

const responseRate = ticketsReceived > 0 ? Math.round((eprPosted / ticketsReceived) * 100) : 100;
const isCompliant = responseRate >= threshold;

return [{
  json: {
    member_name: memberName,
    first_name: firstName,
    email: email,
    station_code: stationCode,
    tickets_received: ticketsReceived,
    epr_posted: eprPosted,
    response_rate: responseRate,
    threshold: threshold,
    is_compliant: isCompliant,
    below_threshold_by: isCompliant ? 0 : threshold - responseRate
  }
}];

const data = $input.first().json;

return [{
  json: {
    status: 'COMPLIANT - NO EMAIL NEEDED',
    member_name: data.member_name,
    email: data.email,
    response_rate: data.response_rate + '%',
    threshold: data.threshold + '%',
    message: `${data.member_name} is at ${data.response_rate}% compliance, which meets or exceeds the ${data.threshold}% threshold.`
  }
}];
